module RefModule (
    input clk,
    input clr,
    input en,
    output [11:0] q
);

    reg [11:0] obf_q_reg;

    always @(posedge clk) begin
        if (clr)
            obf_q_reg <= 12'b0;
        else if (en)
            obf_q_reg <= obf_q_reg + 1;
    end

    assign q = obf_q_reg;

endmodule
